<script>
export default {
  name: "OptionsEyes",
  methods: {
    deleteClass() {
      let c = document.getElementById('eyes').children, i;
      for (i = 0; i < c.length; i++) {
        c[i].classList.remove('show');
      }
    },
    showDefault() {
      this.deleteClass();
      document.querySelector('#e_default').classList.add('show');
    },
    showCrossedEyes() {
      this.deleteClass();
      document.querySelector('#e_crossedeyes').classList.add('show');
    },
    showFoundersEyes() {
      this.deleteClass();
      document.querySelector('#e_founderseyes').classList.add('show');
    },
    showWhiteEyes(){
      this.deleteClass();
      document.querySelector('#e_whiteeyes').classList.add('show');
    },
    showBurningEyes(){
      this.deleteClass();
      document.querySelector('#e_burningeyes').classList.add('show');
    }
  }
}
</script>
